import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import API from '../api/axios';

export default function BookAppointment() {
  const { serviceId } = useParams();
  const navigate = useNavigate();
  const [service, setService] = useState(null);
  const [date, setDate] = useState('');
  const [timeSlot, setTimeSlot] = useState('');
  const [notes, setNotes] = useState('');

  useEffect(() => {
    API.get('/services').then(res => {
      const found = res.data.find(s => s._id === serviceId);
      setService(found);
    });
  }, [serviceId]);

  const handleBook = async () => {
    if (!date || !timeSlot) return toast.error('Please select date and time');
    try {
      await API.post('/appointments', {
        serviceId,
        providerId: service.provider._id,
        date, timeSlot, notes
      });
      toast.success('Appointment booked!');
      navigate('/my-appointments');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Booking failed');
    }
  };

  if (!service) return <p style={{ padding: 40 }}>Loading...</p>;

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Book: {service.name}</h2>
        <p>Provider: <strong>{service.provider?.name}</strong></p>
        <p>Duration: {service.duration} mins | Price: ₹{service.price}</p>
        <hr />
        <label style={styles.label}>Select Date</label>
        <input type="date" style={styles.input}
          min={new Date().toISOString().split('T')[0]}
          onChange={e => setDate(e.target.value)} />

        <label style={styles.label}>Select Time Slot</label>
        <select style={styles.input} onChange={e => setTimeSlot(e.target.value)}>
          <option value="">-- Choose a slot --</option>
          {service.availableSlots?.map(slot => (
            <option key={slot} value={slot}>{slot}</option>
          ))}
        </select>

        <label style={styles.label}>Notes (optional)</label>
        <textarea style={styles.input} rows={3} placeholder="Any special requests..."
          onChange={e => setNotes(e.target.value)} />

        <button style={styles.btn} onClick={handleBook}>Confirm Booking</button>
      </div>
    </div>
  );
}

const styles = {
  container: { display: 'flex', justifyContent: 'center', padding: '40px', background: '#f0f4ff', minHeight: '90vh' },
  card: { background: '#fff', padding: '36px', borderRadius: '12px', boxShadow: '0 4px 20px rgba(0,0,0,0.1)', width: '440px', display: 'flex', flexDirection: 'column', gap: '12px' },
  title: { color: '#1a73e8', margin: 0 },
  label: { fontWeight: 'bold', fontSize: '14px' },
  input: { padding: '10px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '14px', width: '100%' },
  btn: { background: '#1a73e8', color: '#fff', padding: '12px', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', marginTop: '8px' }
};
